class CreditOperation(Account):
    """Credit account operation"""
    __accounts__ = ['credit'] + Account.get_availables()

    def can_process(self, date):  # Cannot withdraw or transfer 31 days after
        return super().can_process(date) and date <= date.today()


class DebitOperation(Account):
    """Debit account operation"""
    __accounts__ = ['debit'] + Account.get_availables()

    def can_process(self, date):  # Cannot withdraw or transfer 31 days after
        return super().can_process(date) and date <= date.today()


class TransferOperation(Account):
    """Transfer account operation"""
    __accounts__ = ['debit', 'credit'] + Account.get_availables()

    def can_process(self, date):  # Cannot withdraw or transfer 31 days after
        return super().can_process(date) and date <= date.today()


